urlset:

{% for url in static_urls %}

  {{ protocol }}://{{ domain }}{{ url.url }}
  {{ url.changefreq }}
  {{ url.priority }}

{% endfor %}


{% for listing in listings %}

  {{ protocol }}://{{ domain }}/listings/{{ listing.slug }}/
  {{ listing.list_date|date:'c' }}
  weekly
  0.7

{% endfor %}


{% for service in services %}

  {{ protocol }}://{{ domain }}/services/{{ service.slug }}/
  {{ service.updated_at|date:'c' }}
  monthly
  0.6

{% endfor %}


{% for blog in blogs %}

  {{ protocol }}://{{ domain }}/blog/{{ blog.slug }}/
  {{ blog.posted_at|date:'c' }}
  monthly
  0.5

{% endfor %}


{% for legal in legal_pages %}

  {{ protocol }}://{{ domain }}/legal/{{ legal.slug }}/
  {{ legal.last_updated|date:'c' }}
  yearly
  0.3

{% endfor %}


{% for custom in custom_urls %}

  {{ protocol }}://{{ domain }}{{ custom.url }}
  {{ custom.last_modified|date:'c' }}
  {{ custom.changefreq }}
  {{ custom.priority }}

{% endfor %}
